// 요청에서 데이터 추출 및 유효성 검사
const body = $input.first().json.body;

const prompt = body?.prompt || body?.message || '';
const model = body?.model || 'llama3.2';  // 기본 모델
const systemPrompt = body?.system_prompt || '당신은 도움이 되는 한국어 AI 어시스턴트입니다. 친절하고 정확하게 답변해주세요.';
const temperature = body?.temperature || 0.7;
const maxTokens = body?.max_tokens || 2000;
const conversationHistory = body?.history || [];

// 지원 모델 목록
const supportedModels = {
  'llama3.2': { name: 'LLaMA 3.2 (3B)', description: '빠른 응답, 일반 대화' },
  'llama3.2:1b': { name: 'LLaMA 3.2 1B', description: '초경량, 빠른 응답' },
  'llama3.1:8b': { name: 'LLaMA 3.1 (8B)', description: '균형잡힌 성능' },
  'codellama': { name: 'Code LLaMA', description: '코드 생성 특화' },
  'mistral': { name: 'Mistral 7B', description: '고품질 텍스트 생성' }
};

if (!prompt || prompt.trim() === '') {
  throw new Error('prompt 또는 message 필드가 필요합니다.');
}

// 모델 유효성 검사
const validModel = supportedModels[model] ? model : 'llama3.2';

// 대화 히스토리 포맷팅
let formattedHistory = '';
if (conversationHistory.length > 0) {
  formattedHistory = conversationHistory
    .map(h => `${h.role === 'user' ? '사용자' : 'AI'}: ${h.content}`)
    .join('\n');
  formattedHistory = '\n\n이전 대화:\n' + formattedHistory + '\n';
}

return [{
  json: {
    prompt: prompt.trim(),
    model: validModel,
    modelInfo: supportedModels[validModel],
    systemPrompt,
    temperature,
    maxTokens,
    formattedHistory,
    conversationHistory,
    timestamp: new Date().toISOString()
  }
}];

