// Generate API 응답 처리
const ollamaResponse = $('🦙 Ollama API 호출').item.json;
const inputData = $('🔍 입력 검증 & 파싱').item.json;

const responseText = ollamaResponse.response || '응답을 받지 못했습니다.';

// 새 히스토리 구성
const updatedHistory = [
  ...inputData.conversationHistory,
  { role: 'user', content: inputData.prompt },
  { role: 'assistant', content: responseText }
];

// 히스토리 최대 10턴 유지
const trimmedHistory = updatedHistory.slice(-20);

return [{
  json: {
    success: true,
    response: responseText,
    model: inputData.model,
    model_info: inputData.modelInfo,
    api_type: 'generate',
    prompt_tokens: ollamaResponse.prompt_eval_count || 0,
    completion_tokens: ollamaResponse.eval_count || 0,
    total_duration_ms: Math.round((ollamaResponse.total_duration || 0) / 1000000),
    history: trimmedHistory,
    timestamp: inputData.timestamp
  }
}];

// Chat API 응답 처리
const ollamaResponse = $('💬 Ollama Chat API').item.json;
const inputData = $('🔍 입력 검증 & 파싱').item.json;

const responseText = ollamaResponse.message?.content || '응답을 받지 못했습니다.';

// 새 히스토리 구성
const updatedHistory = [
  ...inputData.conversationHistory,
  { role: 'user', content: inputData.prompt },
  { role: 'assistant', content: responseText }
];

// 히스토리 최대 10턴 유지
const trimmedHistory = updatedHistory.slice(-20);

return [{
  json: {
    success: true,
    response: responseText,
    model: inputData.model,
    model_info: inputData.modelInfo,
    api_type: 'chat',
    prompt_tokens: ollamaResponse.prompt_eval_count || 0,
    completion_tokens: ollamaResponse.eval_count || 0,
    total_duration_ms: Math.round((ollamaResponse.total_duration || 0) / 1000000),
    history: trimmedHistory,
    timestamp: inputData.timestamp
  }
}];

const ollamaModels = $input.first().json.models || [];

const formattedModels = ollamaModels.map(m => ({
  name: m.name,
  size_gb: (m.size / 1024 / 1024 / 1024).toFixed(2),
  modified: m.modified_at,
  family: m.details?.family || 'unknown'
}));

return [{
  json: {
    success: true,
    available_models: formattedModels,
    count: formattedModels.length,
    recommended: [
      { model: 'llama3.2', use_case: '일반 대화 (빠름)' },
      { model: 'llama3.1:8b', use_case: '복잡한 추론' },
      { model: 'codellama', use_case: '코드 생성' },
      { model: 'mistral', use_case: '고품질 텍스트' }
    ]
  }
}];
